#include <stdio.h>
#include <stdlib.h>
int N;
void sortArrayByParity(int* nums) {
    int* result = (int*)malloc(N * sizeof(int));
    int left = 0, right = N - 1;

    for (int i = 0; i < N; i++) {
        if (nums[i] % 2 != 0) {
            result[left++] = nums[i];
        } else {
            result[right--] = nums[i];
        }
    }

    // Reverse the even part to maintain relative order
    for (int i = 0; i < (N - left) / 2; i++) {
        int temp = result[left + i];
        result[left + i] = result[N - 1 - i];
        result[N - 1 - i] = temp;
    }

    for (int i = 0; i < N; i++) {
        nums[i] = result[i];
    }

    free(result);
}

int main() {
    int n;
    scanf("%d", &n);
    N=n;
    int* nums = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &nums[i]);
    }

    sortArrayByParity(nums);

    for (int i = 0; i < N; i++) {
        printf("%d ", nums[i]);
    }

    free(nums);
    return 0;
}

